export interface RawRow {
  [key: string]: string | number | undefined;
}

export interface InventoryItem {
  id: string; // generated UUID or index
  sku: string;
  dc: string;
  demandType: string;
  mohTotal: number;
  accuracy: number;
  onHand: number;
  threeMonthActuals: number;
  originalData: RawRow;
}

export enum RiskCategory {
  SHORTFALL = 'Potential Shortfall',
  OVERSUPPLY = 'Oversupply',
  DEAD_STOCK = 'Dead Stock',
  HEALTHY = 'Healthy'
}

export interface AnalysisResult {
  item: InventoryItem;
  risks: RiskCategory[];
}

export interface AggregatedAnalysis {
  shortfall: AnalysisResult[];
  oversupply: AnalysisResult[];
  deadStock: AnalysisResult[];
  totalItems: number;
}

import { read, utils } from 'xlsx';
import { InventoryItem, RawRow, AnalysisResult, RiskCategory, AggregatedAnalysis } from '../types';

// Helper to normalize headers for fuzzy matching
const normalize = (str: string) => str.toLowerCase().replace(/[^a-z0-9]/g, '');

const COLUMN_MAPPING = {
  sku: ['sku', 'item', 'product', 'material'],
  dc: ['rowlabels', 'dc', 'location', 'site', 'plant'],
  demandType: ['demandtype', 'type', 'category'],
  mohTotal: ['moh', 'monthsonhand', 'transit', 'moh+intransit', 'totalmoh'],
  accuracy: ['accuracy', 'forecastaccuracy', '3mactualsvforecast', 'acc'],
  onHand: ['onhand', 'stock', 'quantity', 'oh'],
  threeMonthActuals: ['3mactuals', 'sales', 'usage', 'consumption', 'demand']
};

const findKey = (row: RawRow, possibleKeys: string[]): string | undefined => {
  const rowKeys = Object.keys(row);
  return rowKeys.find(key => possibleKeys.some(pk => normalize(key).includes(pk)));
};

export const parseFile = async (file: File): Promise<InventoryItem[]> => {
  const data = await file.arrayBuffer();
  const workbook = read(data);
  const sheetName = workbook.SheetNames[0];
  const worksheet = workbook.Sheets[sheetName];
  const jsonData = utils.sheet_to_json<RawRow>(worksheet);

  if (jsonData.length === 0) return [];

  // Determine column mapping from the first row
  const firstRow = jsonData[0];
  const map: Record<keyof typeof COLUMN_MAPPING, string | undefined> = {
    sku: findKey(firstRow, COLUMN_MAPPING.sku),
    dc: findKey(firstRow, COLUMN_MAPPING.dc),
    demandType: findKey(firstRow, COLUMN_MAPPING.demandType),
    mohTotal: findKey(firstRow, COLUMN_MAPPING.mohTotal),
    accuracy: findKey(firstRow, COLUMN_MAPPING.accuracy),
    onHand: findKey(firstRow, COLUMN_MAPPING.onHand),
    threeMonthActuals: findKey(firstRow, COLUMN_MAPPING.threeMonthActuals),
  };

  return jsonData.map((row, index) => {
    const getItem = (key: string | undefined) => (key && row[key] !== undefined ? row[key] : 0);
    const getString = (key: string | undefined) => (key && row[key] ? String(row[key]) : 'Unknown');

    // Parse percentages if they come in as strings like "80%"
    let acc = getItem(map.accuracy);
    if (typeof acc === 'string') {
      if (acc.includes('%')) {
        acc = parseFloat(acc.replace('%', '')) / 100;
      } else {
        acc = parseFloat(acc);
      }
    }

    return {
      id: `row-${index}`,
      sku: getString(map.sku),
      dc: getString(map.dc),
      demandType: getString(map.demandType),
      mohTotal: Number(getItem(map.mohTotal)),
      accuracy: Number(acc),
      onHand: Number(getItem(map.onHand)),
      threeMonthActuals: Number(getItem(map.threeMonthActuals)),
      originalData: row,
    };
  });
};

export const analyzeInventory = (items: InventoryItem[]): AggregatedAnalysis => {
  const shortfall: AnalysisResult[] = [];
  const oversupply: AnalysisResult[] = [];
  const deadStock: AnalysisResult[] = [];

  items.forEach(item => {
    const risks: RiskCategory[] = [];

    // Rule 1: Potential Shortfall
    // moh_total < 2 AND accuracy >= 0.8
    if (item.mohTotal < 2 && item.accuracy >= 0.8) {
      risks.push(RiskCategory.SHORTFALL);
      shortfall.push({ item, risks: [RiskCategory.SHORTFALL] });
    }

    // Rule 2: Oversupply
    // moh_total > 2 AND accuracy < 0.8
    if (item.mohTotal > 2 && item.accuracy < 0.8) {
      risks.push(RiskCategory.OVERSUPPLY);
      oversupply.push({ item, risks: [RiskCategory.OVERSUPPLY] });
    }

    // Rule 3: Dead Stock
    // On Hand > 0 AND 3m Actuals == 0
    if (item.onHand > 0 && item.threeMonthActuals === 0) {
      risks.push(RiskCategory.DEAD_STOCK);
      deadStock.push({ item, risks: [RiskCategory.DEAD_STOCK] });
    }
  });

  return {
    shortfall,
    oversupply,
    deadStock,
    totalItems: items.length
  };
};

import { GoogleGenAI } from "@google/genai";
import { AggregatedAnalysis, InventoryItem } from "../types";

// Helper to format data for the prompt to avoid token limits with massive datasets
// We prioritize the top 20 most critical items per category for the AI context.
const formatForAI = (analysis: AggregatedAnalysis) => {
  const getTop = (list: any[]) => list.slice(0, 20).map(r => ({
    sku: r.item.sku,
    dc: r.item.dc,
    moh: r.item.mohTotal,
    accuracy: r.item.accuracy,
    onHand: r.item.onHand,
    sales3m: r.item.threeMonthActuals
  }));

  return JSON.stringify({
    summary: {
      totalItems: analysis.totalItems,
      shortfallCount: analysis.shortfall.length,
      oversupplyCount: analysis.oversupply.length,
      deadStockCount: analysis.deadStock.length,
    },
    topShortfalls: getTop(analysis.shortfall),
    topOversupply: getTop(analysis.oversupply),
    topDeadStock: getTop(analysis.deadStock),
  }, null, 2);
};

export const generateExecutiveReport = async (analysis: AggregatedAnalysis): Promise<{ emailText: string; htmlDashboard: string }> => {
  if (!process.env.API_KEY) {
    throw new Error("API Key is missing");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const dataContext = formatForAI(analysis);

  const prompt = `
    You are an expert Inventory Analyst Agent.
    I have performed a deterministic analysis on an inventory dataset and identified risks based on business rules.

    Here is the summary data and the top 20 items for each risk category:
    ${dataContext}

    Please perform two tasks:

    TASK 1: Write an Executive Summary (Email Style).
    - Target audience: Supply Chain Planners.
    - Structure: Group by the three alert types (Potential Shortfall, Oversupply, Dead Stock).
    - Content: 
        - List the count of SKUs found.
        - List the top 10 most critical SKUs for each category from the provided data.
        - Format lines as: [SKU] | DC: [Location] | MOH: [val] | Acc: [val] | OnHand: [val]
    - Tone: Professional, urgent where necessary, concise.

    TASK 2: Generate a Self-Contained Single-File HTML Dashboard code.
    - I want you to write the raw HTML/CSS/JS code for a file that I can save as 'dashboard.html'.
    - It must embed the provided JSON data into a script tag.
    - It should have summary cards at the top.
    - It should have interactive tables (simple JS filtering or just static tables if list is short) for the categories.
    - Use internal CSS for styling (modern, clean, color-coded: Red=Shortfall, Blue=Oversupply, Orange=DeadStock).
    - No external dependencies (no CDN links that might break offline, write simple vanilla JS/CSS).
    - Wrap the HTML code in a markdown code block like \`\`\`html ... \`\`\`.

    Ensure high quality reasoning.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 32768 },
      }
    });

    const text = response.text || "";

    // Extract HTML from the response
    const htmlMatch = text.match(/```html([\s\S]*?)```/);
    const htmlDashboard = htmlMatch ? htmlMatch[1].trim() : "<!-- Error generating dashboard code -->";

    // Remove the HTML block from the text to get just the email summary
    const emailText = text.replace(/```html[\s\S]*?```/g, "").trim();

    return {
      emailText,
      htmlDashboard
    };
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useCallback } from 'react';
import { UploadCloud } from 'lucide-react';
import * as XLSX from 'xlsx'; // Import for type reference if needed, but we use logic in utils

interface FileUploadProps {
  onFileUpload: (file: File) => void;
}

export const FileUpload: React.FC<FileUploadProps> = ({ onFileUpload }) => {
  const handleDrop = useCallback(
    (e: React.DragEvent<HTMLDivElement>) => {
      e.preventDefault();
      e.stopPropagation();
      const files = e.dataTransfer.files;
      if (files && files.length > 0) {
        onFileUpload(files[0]);
      }
    },
    [onFileUpload]
  );

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files && files.length > 0) {
      onFileUpload(files[0]);
    }
  };

  return (
    <div
      onDrop={handleDrop}
      onDragOver={(e) => e.preventDefault()}
      className="border-2 border-dashed border-gray-300 rounded-xl p-12 text-center hover:border-blue-500 hover:bg-blue-50 transition-colors cursor-pointer bg-white shadow-sm"
    >
      <input
        type="file"
        accept=".xlsx, .xls, .csv"
        onChange={handleChange}
        className="hidden"
        id="file-upload"
      />
      <label htmlFor="file-upload" className="cursor-pointer flex flex-col items-center">
        <div className="bg-blue-100 p-4 rounded-full mb-4">
          <UploadCloud className="w-8 h-8 text-blue-600" />
        </div>
        <h3 className="text-xl font-semibold text-gray-800 mb-2">
          Upload Inventory File
        </h3>
        <p className="text-gray-500 max-w-sm mx-auto">
          Drag and drop your Excel or CSV file here, or click to browse.
          Expected columns: SKU, DC, MOH, Accuracy, On Hand, 3m Actuals.
        </p>
      </label>
    </div>
  );
};

import React, { useState } from 'react';
import { AggregatedAnalysis, AnalysisResult, RiskCategory } from '../types';
import { AlertTriangle, TrendingDown, Archive, CheckCircle, Download, FileText } from 'lucide-react';
import { generateExecutiveReport } from '../services/geminiService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface AnalysisDashboardProps {
  analysis: AggregatedAnalysis;
  fileName: string;
  onReset: () => void;
}

export const AnalysisDashboard: React.FC<AnalysisDashboardProps> = ({ analysis, fileName, onReset }) => {
  const [activeTab, setActiveTab] = useState<RiskCategory | 'Overview'>('Overview');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [generatedReport, setGeneratedReport] = useState<{ emailText: string, htmlDashboard: string } | null>(null);

  const handleGenerateReport = async () => {
    setIsGeneratingReport(true);
    try {
      const report = await generateExecutiveReport(analysis);
      setGeneratedReport(report);
    } catch (e) {
      alert("Failed to generate AI report. Check API Key.");
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const downloadHtml = () => {
    if (!generatedReport) return;
    const blob = new Blob([generatedReport.htmlDashboard], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `inventory_dashboard_${new Date().toISOString().split('T')[0]}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  const chartData = [
    { name: 'Shortfall', count: analysis.shortfall.length, color: '#ef4444' },
    { name: 'Oversupply', count: analysis.oversupply.length, color: '#3b82f6' },
    { name: 'Dead Stock', count: analysis.deadStock.length, color: '#f97316' },
  ];

  const renderTable = (data: AnalysisResult[], type: RiskCategory) => (
    <div className="overflow-x-auto">
      <table className="min-w-full divide-y divide-gray-200">
        <thead className="bg-gray-50">
          <tr>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">SKU</th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">DC</th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">MOH</th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Accuracy</th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">On Hand</th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">3m Sales</th>
          </tr>
        </thead>
        <tbody className="bg-white divide-y divide-gray-200">
          {data.map((row, idx) => (
            <tr key={idx} className="hover:bg-gray-50">
              <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">{row.item.sku}</td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{row.item.dc}</td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{row.item.mohTotal.toFixed(2)}</td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{(row.item.accuracy * 100).toFixed(1)}%</td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{row.item.onHand.toLocaleString()}</td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{row.item.threeMonthActuals.toLocaleString()}</td>
            </tr>
          ))}
          {data.length === 0 && (
            <tr>
              <td colSpan={6} className="px-6 py-8 text-center text-sm text-gray-500">No {type.toLowerCase()} alerts found.</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );

  return (
    <div className="space-y-8">
      {/* Header Actions */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-6 rounded-xl shadow-sm border border-gray-200">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">Analysis Results</h2>
          <p className="text-gray-500 text-sm mt-1">File: {fileName} | Total Items: {analysis.totalItems}</p>
        </div>
        <div className="flex gap-3">
           <button
            onClick={onReset}
            className="px-4 py-2 text-gray-600 bg-gray-100 hover:bg-gray-200 rounded-lg text-sm font-medium transition-colors"
          >
            Upload New File
          </button>
          <button
            onClick={handleGenerateReport}
            disabled={isGeneratingReport}
            className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors disabled:opacity-50 text-sm font-medium"
          >
            {isGeneratingReport ? (
              <>Processing...</>
            ) : (
              <>
                <FileText className="w-4 h-4" />
                Generate AI Agent Report
              </>
            )}
          </button>
        </div>
      </div>

      {/* Metric Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <button
          onClick={() => setActiveTab(RiskCategory.SHORTFALL)}
          className={`p-6 rounded-xl border-2 transition-all text-left ${
            activeTab === RiskCategory.SHORTFALL ? 'border-red-500 bg-red-50' : 'border-white bg-white hover:border-red-200'
          } shadow-sm`}
        >
          <div className="flex items-center justify-between mb-4">
            <div className="p-3 bg-red-100 text-red-600 rounded-lg">
              <AlertTriangle className="w-6 h-6" />
            </div>
            <span className="text-3xl font-bold text-gray-900">{analysis.shortfall.length}</span>
          </div>
          <h3 className="text-lg font-semibold text-gray-800">Potential Shortfall</h3>
          <p className="text-sm text-gray-500 mt-1">High risk of stockout</p>
        </button>

        <button
          onClick={() => setActiveTab(RiskCategory.OVERSUPPLY)}
          className={`p-6 rounded-xl border-2 transition-all text-left ${
            activeTab === RiskCategory.OVERSUPPLY ? 'border-blue-500 bg-blue-50' : 'border-white bg-white hover:border-blue-200'
          } shadow-sm`}
        >
          <div className="flex items-center justify-between mb-4">
            <div className="p-3 bg-blue-100 text-blue-600 rounded-lg">
              <TrendingDown className="w-6 h-6" />
            </div>
            <span className="text-3xl font-bold text-gray-900">{analysis.oversupply.length}</span>
          </div>
          <h3 className="text-lg font-semibold text-gray-800">Oversupply</h3>
          <p className="text-sm text-gray-500 mt-1">Excess inventory inefficiency</p>
        </button>

        <button
          onClick={() => setActiveTab(RiskCategory.DEAD_STOCK)}
          className={`p-6 rounded-xl border-2 transition-all text-left ${
            activeTab === RiskCategory.DEAD_STOCK ? 'border-orange-500 bg-orange-50' : 'border-white bg-white hover:border-orange-200'
          } shadow-sm`}
        >
          <div className="flex items-center justify-between mb-4">
            <div className="p-3 bg-orange-100 text-orange-600 rounded-lg">
              <Archive className="w-6 h-6" />
            </div>
            <span className="text-3xl font-bold text-gray-900">{analysis.deadStock.length}</span>
          </div>
          <h3 className="text-lg font-semibold text-gray-800">Dead Stock</h3>
          <p className="text-sm text-gray-500 mt-1">No sales in 3 months</p>
        </button>
      </div>

      {/* Main Content Area */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 min-h-[400px]">
        {/* Tabs Header */}
        <div className="border-b border-gray-200 px-6 py-4 flex gap-6 overflow-x-auto">
             <button
            onClick={() => setActiveTab('Overview')}
            className={`pb-2 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${
              activeTab === 'Overview' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
            Dashboard Overview
          </button>
          {[RiskCategory.SHORTFALL, RiskCategory.OVERSUPPLY, RiskCategory.DEAD_STOCK].map(cat => (
             <button
                key={cat}
                onClick={() => setActiveTab(cat)}
                className={`pb-2 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${
                  activeTab === cat ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
              >
                {cat} List
              </button>
          ))}
        </div>

        {/* Tab Content */}
        <div className="p-6">
          {activeTab === 'Overview' && (
            <div className="space-y-8">
                <div className="h-80 w-full">
                     <h3 className="text-lg font-semibold text-gray-800 mb-4">Risk Distribution</h3>
                     <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={chartData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                            <CartesianGrid strokeDasharray="3 3" vertical={false} />
                            <XAxis dataKey="name" />
                            <YAxis />
                            <Tooltip 
                                contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                cursor={{fill: 'transparent'}}
                            />
                            <Bar dataKey="count" radius={[4, 4, 0, 0]}>
                                {chartData.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={entry.color} />
                                ))}
                            </Bar>
                        </BarChart>
                     </ResponsiveContainer>
                </div>

                {generatedReport && (
                    <div className="bg-slate-50 border border-slate-200 rounded-xl p-6">
                        <div className="flex justify-between items-center mb-4">
                             <h3 className="text-lg font-semibold text-slate-800 flex items-center gap-2">
                                <CheckCircle className="w-5 h-5 text-green-600" />
                                Agent Executive Summary
                             </h3>
                             <button onClick={downloadHtml} className="text-sm flex items-center gap-2 text-blue-600 hover:text-blue-700 font-medium">
                                <Download className="w-4 h-4" />
                                Download Portable HTML
                             </button>
                        </div>
                        <div className="prose prose-sm max-w-none text-slate-700 bg-white p-4 rounded-lg border border-slate-100 shadow-inner whitespace-pre-wrap font-mono">
                            {generatedReport.emailText}
                        </div>
                    </div>
                )}
            </div>
          )}
          {activeTab === RiskCategory.SHORTFALL && renderTable(analysis.shortfall, RiskCategory.SHORTFALL)}
          {activeTab === RiskCategory.OVERSUPPLY && renderTable(analysis.oversupply, RiskCategory.OVERSUPPLY)}
          {activeTab === RiskCategory.DEAD_STOCK && renderTable(analysis.deadStock, RiskCategory.DEAD_STOCK)}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { LayoutDashboard } from 'lucide-react';
import { FileUpload } from './components/FileUpload';
import { AnalysisDashboard } from './components/AnalysisDashboard';
import { parseFile, analyzeInventory } from './utils/dataProcessor';
import { AggregatedAnalysis } from './types';

function App() {
  const [analysis, setAnalysis] = useState<AggregatedAnalysis | null>(null);
  const [fileName, setFileName] = useState<string>("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleFileUpload = async (file: File) => {
    setLoading(true);
    setError(null);
    try {
      setFileName(file.name);
      const items = await parseFile(file);
      if (items.length === 0) {
        setError("No valid data found in file. Please check column headers.");
      } else {
        const result = analyzeInventory(items);
        setAnalysis(result);
      }
    } catch (err) {
      console.error(err);
      setError("Failed to parse file. Please ensure it is a valid Excel or CSV file.");
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setAnalysis(null);
    setFileName("");
    setError(null);
  };

  return (
    <div className="min-h-screen bg-gray-50 pb-12">
      {/* Navigation */}
      <nav className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center gap-3">
              <div className="bg-indigo-600 p-2 rounded-lg">
                <LayoutDashboard className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-xl font-bold text-gray-900">Inventory Alert Agent</h1>
                <p className="text-xs text-gray-500">Supply Chain Risk Analytics</p>
              </div>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-20">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600 mb-4"></div>
            <p className="text-gray-500 font-medium">Analyzing supply chain data...</p>
          </div>
        ) : !analysis ? (
          <div className="max-w-2xl mx-auto space-y-8 mt-10">
            <div className="text-center space-y-2">
              <h2 className="text-3xl font-bold text-gray-900">Start Your Analysis</h2>
              <p className="text-gray-600">Upload your inventory data to detect Shortfalls, Oversupply, and Dead Stock instantly.</p>
            </div>

            <FileUpload onFileUpload={handleFileUpload} />

            {error && (
