                    <li><span className="font-medium text-gray-900">Row Labels/DC:</span> Location</li>
                    <li><span className="font-medium text-gray-900">MOH (Total):</span> Months on Hand + Transit</li>
                    <li><span className="font-medium text-gray-900">Accuracy:</span> Forecast Accuracy (e.g. 0.8 or 80%)</li>
                    <li><span className="font-medium text-gray-900">On Hand:</span> Current Quantity</li>
                    <li><span className="font-medium text-gray-900">3m Actuals:</span> Sales/Usage last 3 months</li>
                </ul>
            </div>
          </div>
        ) : (
          <AnalysisDashboard 
            analysis={analysis} 
            fileName={fileName} 
            onReset={handleReset} 
          />
        )}
      </main>
    </div>
  );
}

