import { GoogleGenAI } from "@google/genai";
import { AggregatedAnalysis, InventoryItem } from "../types";

// Helper to format data for the prompt to avoid token limits with massive datasets
// We prioritize the top 20 most critical items per category for the AI context.
const formatForAI = (analysis: AggregatedAnalysis) => {
  const getTop = (list: any[]) => list.slice(0, 20).map(r => ({
    sku: r.item.sku,
    dc: r.item.dc,
    demandType: r.item.demandType,
    moh: r.item.mohTotal,
    accuracy: r.item.accuracy,
    onHand: r.item.onHand,
    sales3m: r.item.threeMonthActuals,
    supplier: r.item.supplier,
    leadTime: r.item.leadTime,
    otd: r.item.otd
  }));

  return JSON.stringify({
    summary: {
      totalItems: analysis.totalItems,
      shortfallCount: analysis.shortfall.length,
      oversupplyCount: analysis.oversupply.length,
      deadStockCount: analysis.deadStock.length,
      supplierRiskCount: analysis.supplierRisk.length
    },
    topShortfalls: getTop(analysis.shortfall),
    topOversupply: getTop(analysis.oversupply),
    topDeadStock: getTop(analysis.deadStock),
    topSupplierRisks: getTop(analysis.supplierRisk)
  }, null, 2);
};

export const generateExecutiveReport = async (analysis: AggregatedAnalysis): Promise<{ emailText: string; htmlDashboard: string }> => {
  if (!process.env.API_KEY) {
    throw new Error("API Key is missing");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const dataContext = formatForAI(analysis);

  const prompt = `
    You are an expert Inventory Analyst Agent.
    I have performed a deterministic analysis on an inventory dataset and identified risks based on business rules.

    Here is the summary data and the top 20 items for each risk category:
    ${dataContext}

    Please perform two tasks:

    TASK 1: Write an Executive Summary (Email Style).
    - Target audience: Supply Chain Planners.
    - Structure: 
        1. **Overview**: Brief summary of the health of the inventory.
        2. **Risk Category Deep Dives**: Group by Shortfall, Oversupply, Dead Stock, and Supplier Risk.
        3. **Forecasting & Seasonality Insights**: 
           - Analyze the "Demand Type", "Accuracy", and "Sales" data to identify SKUs that may be exhibiting seasonal volatility or trend changes that the current model is missing. 
           - Highlight specific SKUs where Forecast Accuracy is low (< 80%) despite high sales, suggesting a model fit issue.
           - Recommend specific forecasting model improvements (e.g., enable seasonality factors, adjust safety stock for lead time variance, shorten review periods).
    - Content for each Category: 
        - List the count of SKUs found.
        - List the top 5-10 most critical SKUs.
        - Include Supplier details (Lead Time/OTD) where relevant.
        - Format lines as: [SKU] | Type: [DemandType] | DC: [Loc] | MOH: [val] | Acc: [val] | Supplier: [Name]
    - Tone: Professional, urgent where necessary, concise.

    TASK 2: Generate a Self-Contained Single-File HTML Dashboard code.
    - I want you to write the raw HTML/CSS/JS code for a file that I can save as 'dashboard.html'.
    - It must embed the provided JSON data into a script tag.
    - It should have summary cards at the top for all 4 categories.
    - It should have interactive tables including the "Demand Type" column.
    - Use internal CSS for styling (modern, clean, color-coded: Red=Shortfall, Blue=Oversupply, Orange=DeadStock, Purple=SupplierRisk).
    - No external dependencies (no CDN links that might break offline, write simple vanilla JS/CSS).
    - Wrap the HTML code in a markdown code block like \`\`\`html ... \`\`\`.

    Ensure high quality reasoning.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 32768 },
      }
    });

    const text = response.text || "";

    // Extract HTML from the response
    const htmlMatch = text.match(/```html([\s\S]*?)```/);
    const htmlDashboard = htmlMatch ? htmlMatch[1].trim() : "<!-- Error generating dashboard code -->";

    // Remove the HTML block from the text to get just the email summary
    const emailText = text.replace(/```html[\s\S]*?```/g, "").trim();

    return {
      emailText,
      htmlDashboard
    };
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

