export const generateExecutiveReport = async (analysis: AggregatedAnalysis, accessToken: string): Promise<{ emailText: string; htmlDashboard: string }> => {
  // Format the data on the client side to prepare the payload
  const dataContext = formatForAI(analysis);

  try {
    // Send data to the secure Python backend with the Access Token
    const response = await fetch('/api/generate-report', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-Access-Token': accessToken
      },
      body: JSON.stringify({ context: dataContext }),
    });

    if (response.status === 401) {
      throw new Error("Invalid Access Token. Please check your code.");
    }

    if (!response.ok) {
      throw new Error(`Server error: ${response.statusText}`);
    }

    const result = await response.json();
    return result; // Expecting { emailText: string, htmlDashboard: string }
