import React, { useState } from 'react';
import { AggregatedAnalysis, AnalysisResult, RiskCategory } from '../types';
import { AlertTriangle, TrendingDown, Archive, CheckCircle, Download, FileText, Truck, BarChart2, ScatterChart as ScatterIcon, Lock } from 'lucide-react';
import { generateExecutiveReport } from '../services/geminiService';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell,
  ScatterChart, Scatter, Label, Legend, ReferenceLine
} from 'recharts';

interface AnalysisDashboardProps {
  analysis: AggregatedAnalysis;
  fileName: string;
  onReset: () => void;
}

export const AnalysisDashboard: React.FC<AnalysisDashboardProps> = ({ analysis, fileName, onReset }) => {
  const [activeTab, setActiveTab] = useState<RiskCategory | 'Overview'>('Overview');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [generatedReport, setGeneratedReport] = useState<{ emailText: string, htmlDashboard: string } | null>(null);

  // State for Access Token
  const [accessToken, setAccessToken] = useState("");
  const [authError, setAuthError] = useState<string | null>(null);

  const handleGenerateReport = async () => {
    if (!accessToken.trim()) {
      setAuthError("Access Token is required");
      return;
    }

    setIsGeneratingReport(true);
    setAuthError(null);
    try {
      const report = await generateExecutiveReport(analysis, accessToken);
      setGeneratedReport(report);
    } catch (e: any) {
      setAuthError(e.message || "Failed to generate AI report.");
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const downloadHtml = () => {
    if (!generatedReport) return;
    const blob = new Blob([generatedReport.htmlDashboard], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `inventory_dashboard_${new Date().toISOString().split('T')[0]}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  const chartData = [
    { name: 'Shortfall', count: analysis.shortfall.length, color: '#ef4444' },
    { name: 'Oversupply', count: analysis.oversupply.length, color: '#3b82f6' },
    { name: 'Dead Stock', count: analysis.deadStock.length, color: '#f97316' },
    { name: 'Supplier Risk', count: analysis.supplierRisk.length, color: '#9333ea' },
  ];

  // Data for Supplier Scatter Plot (Lead Time vs OTD)
  // Filter for valid data points to avoid clustering at 0
  const supplierScatterData = analysis.allItems
    .filter(item => item.leadTime > 0 && item.supplier !== 'N/A' && item.supplier !== 'Unknown')
    .map(item => ({
      x: item.leadTime,
      y: item.otd * 100,
      name: item.supplier,
      sku: item.sku,
      risk: (item.leadTime > 60 || item.otd < 0.85) ? 'Risky' : 'Healthy'
    }));

  // Data for Inventory Health Matrix (Accuracy vs MOH)
  const matrixData = analysis.allItems
    .filter(item => item.mohTotal < 24) // Filter out extreme outliers for better visualization
    .map(item => {
      let status = 'Healthy';
      if (item.mohTotal < 2 && item.accuracy >= 0.8) status = 'Shortfall';
      if (item.mohTotal > 2 && item.accuracy < 0.8) status = 'Oversupply';

      return {
        x: item.accuracy * 100,
        y: item.mohTotal,
        z: item.onHand, // bubble size
        status,
        sku: item.sku
      };
    });

  const renderTable = (data: AnalysisResult[], type: RiskCategory) => (
    <div className="overflow-x-auto">
      <table className="min-w-full divide-y divide-gray-200">
        <thead className="bg-gray-50">
          <tr>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">SKU</th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">DC</th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Type</th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">MOH</th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Accuracy</th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">On Hand</th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Supplier</th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Lead Time / OTD</th>
          </tr>
        </thead>
        <tbody className="bg-white divide-y divide-gray-200">
          {data.map((row, idx) => (
            <tr key={idx} className="hover:bg-gray-50">
              <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">{row.item.sku}</td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{row.item.dc}</td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{row.item.demandType}</td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{row.item.mohTotal.toFixed(2)}</td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{(row.item.accuracy * 100).toFixed(1)}%</td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{row.item.onHand.toLocaleString()}</td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{row.item.supplier}</td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                 {row.item.leadTime > 0 ? `${row.item.leadTime}d` : '-'} / {(row.item.otd * 100).toFixed(0)}%
              </td>
            </tr>
          ))}
          {data.length === 0 && (
            <tr>
              <td colSpan={8} className="px-6 py-8 text-center text-sm text-gray-500">No {type.toLowerCase()} alerts found.</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );

  return (
    <div className="space-y-8">
      {/* Header Actions */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-6 rounded-xl shadow-sm border border-gray-200">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">Analysis Results</h2>
          <p className="text-gray-500 text-sm mt-1">File: {fileName} | Total Items: {analysis.totalItems}</p>
        </div>
        <div className="flex flex-col md:flex-row gap-3 items-end md:items-center">
           <button
