      {/* Metric Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <button onClick={() => setActiveTab(RiskCategory.SHORTFALL)} className={`p-6 rounded-xl border-2 transition-all text-left ${activeTab === RiskCategory.SHORTFALL ? 'border-red-500 bg-red-50' : 'border-white bg-white hover:border-red-200'} shadow-sm`}>
