            <span className="text-3xl font-bold text-gray-900">{analysis.shortfall.length}</span>
          </div>
          <h3 className="text-lg font-semibold text-gray-800">Shortfall</h3>
          <p className="text-sm text-gray-500 mt-1">High stockout risk</p>
