        <button onClick={() => setActiveTab(RiskCategory.OVERSUPPLY)} className={`p-6 rounded-xl border-2 transition-all text-left ${activeTab === RiskCategory.OVERSUPPLY ? 'border-blue-500 bg-blue-50' : 'border-white bg-white hover:border-blue-200'} shadow-sm`}>
