import React, { useState } from 'react';
import { LayoutDashboard, Lock, ArrowRight, Loader2 } from 'lucide-react';
import { FileUpload } from './components/FileUpload';
import { AnalysisDashboard } from './components/AnalysisDashboard';
import { parseFile, analyzeInventory } from './utils/dataProcessor';
import { AggregatedAnalysis } from './types';

function App() {
  const [analysis, setAnalysis] = useState<AggregatedAnalysis | null>(null);
  const [fileName, setFileName] = useState<string>("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Auth State
  const [accessToken, setAccessToken] = useState("");
  const [isVerified, setIsVerified] = useState(false);
  const [verifying, setVerifying] = useState(false);
  const [authError, setAuthError] = useState<string | null>(null);

  const handleVerify = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!accessToken.trim()) return;

    setVerifying(true);
    setAuthError(null);

    try {
      const response = await fetch('/api/verify-token', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ token: accessToken })
      });

      if (response.ok) {
        setIsVerified(true);
      } else {
        setAuthError("Invalid Access Code. Please try again.");
      }
    } catch (err) {
      setAuthError("Unable to verify. Check connection.");
    } finally {
      setVerifying(false);
    }
  };

  const handleFileUpload = async (file: File) => {
    setLoading(true);
    setError(null);
    try {
      setFileName(file.name);
      const items = await parseFile(file);
      if (items.length === 0) {
        setError("No valid data found in file. Please check column headers.");
      } else {
        const result = analyzeInventory(items);
        setAnalysis(result);
      }
    } catch (err) {
      console.error(err);
      setError("Failed to parse file. Please ensure it is a valid Excel or CSV file.");
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setAnalysis(null);
    setFileName("");
    setError(null);
    // Note: We keep them logged in (isVerified=true) for convenience
  };

  return (
    <div className="min-h-screen bg-gray-50 pb-12">
      {/* Navigation */}
      <nav className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center gap-3">
              <div className="bg-indigo-600 p-2 rounded-lg">
                <LayoutDashboard className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-xl font-bold text-gray-900">Inventory Alert Agent</h1>
                <p className="text-xs text-gray-500">Supply Chain Risk Analytics</p>
              </div>
            </div>
            {isVerified && (
              <div className="flex items-center gap-2 text-green-600 text-sm font-medium">
                <div className="w-2 h-2 rounded-full bg-green-500"></div>
                Verified Session
              </div>
            )}
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-20">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600 mb-4"></div>
            <p className="text-gray-500 font-medium">Analyzing supply chain data...</p>
          </div>
        ) : !analysis ? (
          <div className="max-w-2xl mx-auto space-y-8 mt-10">
            <div className="text-center space-y-2">
              <h2 className="text-3xl font-bold text-gray-900">Start Your Analysis</h2>
              <p className="text-gray-600">
                {isVerified 
                  ? "Upload your inventory data to detect Shortfalls, Oversupply, Dead Stock, and Supplier Risks instantly."
                  : "Please enter your access code to proceed with the analysis tool."}
              </p>
            </div>

            {!isVerified ? (
              <div className="bg-white p-8 rounded-xl border border-gray-200 shadow-sm max-w-md mx-auto">
                <form onSubmit={handleVerify} className="space-y-4">
                  <div>
                    <label htmlFor="access-code" className="block text-sm font-medium text-gray-700 mb-1">
                      Access Code
                    </label>
                    <div className="relative">
                      <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Lock className="h-5 w-5 text-gray-400" />
                      </div>
                      <input
                        type="password"
                        id="access-code"
                        className="block w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg focus:ring-indigo-500 focus:border-indigo-500 text-sm"
                        placeholder="Enter code provided by admin"
                        value={accessToken}
                        onChange={(e) => setAccessToken(e.target.value)}
                      />
                    </div>
                  </div>

                  {authError && (
                    <div className="text-sm text-red-600 bg-red-50 p-2 rounded">
                      {authError}
                    </div>
                  )}

                  <button
                    type="submit"
                    disabled={verifying || !accessToken}
                    className="w-full flex justify-center items-center py-2.5 px-4 border border-transparent rounded-lg shadow-sm text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                  >
                    {verifying ? (
                      <>
                        <Loader2 className="animate-spin -ml-1 mr-2 h-4 w-4" />
                        Verifying...
                      </>
                    ) : (
                      <>
                        Continue
                        <ArrowRight className="ml-2 h-4 w-4" />
                      </>
                    )}
                  </button>
                </form>
              </div>
            ) : (
              <>
                <FileUpload onFileUpload={handleFileUpload} />

                {error && (
                  <div className="p-4 bg-red-50 text-red-700 rounded-lg border border-red-200 text-center">
                    {error}
                  </div>
                )}

                <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm text-left">
                    <h3 className="font-semibold text-gray-800 mb-3">Expected Data Format</h3>
                    <ul className="text-sm text-gray-600 space-y-2 list-disc pl-5">
                        <li><span className="font-medium text-gray-900">SKU:</span> Identifier</li>
                        <li><span className="font-medium text-gray-900">Row Labels/DC:</span> Location</li>
                        <li><span className="font-medium text-gray-900">MOH (Total):</span> Months on Hand + Transit</li>
                        <li><span className="font-medium text-gray-900">Accuracy:</span> Forecast Accuracy (e.g. 0.8 or 80%)</li>
                        <li><span className="font-medium text-gray-900">On Hand:</span> Current Quantity</li>
                        <li><span className="font-medium text-gray-900">3m Actuals:</span> Sales/Usage last 3 months</li>
                        <li className="text-indigo-600 font-medium pt-2">Optional Supplier Columns:</li>
                        <li><span className="font-medium text-gray-900">Supplier:</span> Vendor Name</li>
                        <li><span className="font-medium text-gray-900">Lead Time:</span> Days (e.g. 60)</li>
                        <li><span className="font-medium text-gray-900">OTD:</span> On-Time Delivery % (e.g. 0.95 or 95%)</li>
                    </ul>
                </div>
              </>
            )}
          </div>
        ) : (
          <AnalysisDashboard 
            analysis={analysis} 
            fileName={fileName} 
            accessToken={accessToken}
            onReset={handleReset} 
          />
        )}
      </main>
    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { AggregatedAnalysis, AnalysisResult, RiskCategory } from '../types';
import { AlertTriangle, TrendingDown, Archive, CheckCircle, Download, FileText, Truck, BarChart2, ScatterChart as ScatterIcon } from 'lucide-react';
import { generateExecutiveReport } from '../services/geminiService';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell,
  ScatterChart, Scatter, Label, Legend, ReferenceLine
} from 'recharts';

interface AnalysisDashboardProps {
  analysis: AggregatedAnalysis;
  fileName: string;
  accessToken: string; // Passed from App parent
  onReset: () => void;
}

export const AnalysisDashboard: React.FC<AnalysisDashboardProps> = ({ analysis, fileName, accessToken, onReset }) => {
  const [activeTab, setActiveTab] = useState<RiskCategory | 'Overview'>('Overview');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [generatedReport, setGeneratedReport] = useState<{ emailText: string, htmlDashboard: string } | null>(null);
  const [authError, setAuthError] = useState<string | null>(null);

  const handleGenerateReport = async () => {
    setIsGeneratingReport(true);
    setAuthError(null);
    try {
      // Use the accessToken prop passed from the main App component
      const report = await generateExecutiveReport(analysis, accessToken);
      setGeneratedReport(report);
    } catch (e: any) {
      setAuthError(e.message || "Failed to generate AI report.");
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const downloadHtml = () => {
    if (!generatedReport) return;
    const blob = new Blob([generatedReport.htmlDashboard], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `inventory_dashboard_${new Date().toISOString().split('T')[0]}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  const chartData = [
    { name: 'Shortfall', count: analysis.shortfall.length, color: '#ef4444' },
    { name: 'Oversupply', count: analysis.oversupply.length, color: '#3b82f6' },
    { name: 'Dead Stock', count: analysis.deadStock.length, color: '#f97316' },
    { name: 'Supplier Risk', count: analysis.supplierRisk.length, color: '#9333ea' },
  ];

  // Data for Supplier Scatter Plot (Lead Time vs OTD)
  // Filter for valid data points to avoid clustering at 0
  const supplierScatterData = analysis.allItems
    .filter(item => item.leadTime > 0 && item.supplier !== 'N/A' && item.supplier !== 'Unknown')
    .map(item => ({
      x: item.leadTime,
      y: item.otd * 100,
      name: item.supplier,
      sku: item.sku,
      risk: (item.leadTime > 60 || item.otd < 0.85) ? 'Risky' : 'Healthy'
    }));

  // Data for Inventory Health Matrix (Accuracy vs MOH)
  const matrixData = analysis.allItems
    .filter(item => item.mohTotal < 24) // Filter out extreme outliers for better visualization
    .map(item => {
      let status = 'Healthy';
      if (item.mohTotal < 2 && item.accuracy >= 0.8) status = 'Shortfall';
      if (item.mohTotal > 2 && item.accuracy < 0.8) status = 'Oversupply';

      return {
        x: item.accuracy * 100,
        y: item.mohTotal,
        z: item.onHand, // bubble size
        status,
        sku: item.sku
      };
    });

  const renderTable = (data: AnalysisResult[], type: RiskCategory) => (
    <div className="overflow-x-auto">
      <table className="min-w-full divide-y divide-gray-200">
        <thead className="bg-gray-50">
