        data = request.get_json(force=True, silent=True)
        if not data:
            return jsonify({"valid": False, "error": "Invalid JSON body"}), 400

        token = data.get('token')
        logger.info(f"Verification attempt with token: {token}")

        if str(token) == str(ACCESS_TOKEN):
            return jsonify({"valid": True})

        return jsonify({"valid": False, "error": "Unauthorized"}), 401

    except Exception as e:
        logger.error(f"Error verifying token: {e}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/generate-report', methods=['POST'])
def generate_report():
    client_token = request.headers.get('X-Access-Token')

    if not client_token or client_token != ACCESS_TOKEN:
        return jsonify({"error": "Unauthorized: Invalid Access Token"}), 401

    try:
        # Initialize client inside the route to prevent startup failures
        api_key = os.environ.get("API_KEY")
        if not api_key:
            return jsonify({"error": "Server configuration error: API_KEY missing"}), 500

        client = genai.Client(api_key=api_key)

        data = request.get_json(force=True, silent=True)
        if not data:
             return jsonify({"error": "Invalid JSON body"}), 400

        data_context = data.get('context', '')

        prompt = f"""
        You are an expert Inventory Analyst Agent.
        Perform a professional supply chain analysis.

        Summary Data:
        {data_context}

        TASK 1: Write an Executive Summary (Email Style).
        TASK 2: Generate a Self-Contained Single-File HTML Dashboard code in a markdown block.
        """

        response = client.models.generate_content(
            model='gemini-2.0-flash', 
            contents=prompt
        )

        text = response.text or ""
        html_match = re.search(r'```html([\s\S]*?)```', text)
        html_dashboard = html_match.group(1).strip() if html_match else "<!-- Error generating dashboard -->"
        email_text = re.sub(r'```html[\s\S]*?```', '', text).strip()

        return jsonify({
            "emailText": email_text,
            "htmlDashboard": html_dashboard
        })

    except Exception as e:
        logger.error(f"Generate report error: {e}")
        return jsonify({"error": str(e)}), 500

if __name__ == '__main__':
