  const handleVerify = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!accessToken.trim()) return;

    setVerifying(true);
    setAuthError(null);

    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 10000); // 10s timeout

    try {
      const response = await fetch('/api/verify-token', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ token: accessToken }),
        signal: controller.signal
      });

      clearTimeout(timeoutId);

      // Check if response is JSON
      const contentType = response.headers.get("content-type");
      if (!contentType || !contentType.includes("application/json")) {
        const text = await response.text();
        console.error("Server returned non-JSON:", text);
        throw new Error("Server configuration error (Non-JSON response)");
      }

      const data = await response.json();

      if (response.ok && data.valid) {
        setIsVerified(true);
      } else {
        setAuthError(data.error || "Invalid Access Code. Please try again.");
      }
    } catch (err: any) {
      console.error("Verification error:", err);
      if (err.name === 'AbortError') {
        setAuthError("Connection timed out. Is the backend running?");
      } else {
        setAuthError(err.message || "Connection failed. Please check the server status.");
      }
    } finally {
      setVerifying(false);
    }
  };

  const handleFileUpload = async (file: File) => {
    setLoading(true);
    setError(null);
    try {
      setFileName(file.name);
      const items = await parseFile(file);
      if (items.length === 0) {
        setError("No valid data found in file. Please check column headers.");
      } else {
        const result = analyzeInventory(items);
        setAnalysis(result);
      }
    } catch (err) {
      console.error(err);
      setError("Failed to parse file. Please ensure it is a valid Excel or CSV file.");
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setAnalysis(null);
    setFileName("");
    setError(null);
  };

