            <div className="text-center space-y-2">
              <h2 className="text-3xl font-bold text-gray-900">Start Your Analysis</h2>
              <p className="text-gray-600">
                {isVerified 
                  ? "Upload your inventory data to detect Shortfalls, Oversupply, Dead Stock, and Supplier Risks instantly."
                  : "Please enter your access code to proceed with the analysis tool."}
