    setAuthError(null);

    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 10000); 

    try {
      const apiUrl = getApiUrl('/api/verify-token');
      console.log(`Requesting verification from: ${apiUrl}`);

      const response = await fetch(apiUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ token: accessToken }),
        signal: controller.signal
      });

      clearTimeout(timeoutId);

      // Check if response is actually JSON before parsing
      const contentType = response.headers.get("content-type");
      if (!contentType || !contentType.includes("application/json")) {
        const rawBody = await response.text();
        console.error("Received non-JSON response from server:", rawBody);

        // Help user identify if it's a 404 or an error page
        const errorSnippet = rawBody.substring(0, 150).replace(/</g, "&lt;");
        throw new Error(`Server returned HTML/Text instead of JSON. This usually means the Python backend (app.py) is not running or the URL is incorrect. (Response start: ${errorSnippet}...)`);
      }

      const data = await response.json();

      if (response.ok && data.valid) {
        setIsVerified(true);
      } else {
        setAuthError(data.error || "Access code verification failed.");
      }
    } catch (err: any) {
      console.error("Verification error details:", err);
      if (err.name === 'AbortError') {
        setAuthError("Server request timed out. Is 'python app.py' running?");
      } else {
        setAuthError(err.message || "Failed to connect to the server. Ensure the backend is running.");
      }
    } finally {
      setVerifying(false);
    }
  };

  const handleFileUpload = async (file: File) => {
    setLoading(true);
    setError(null);
    try {
      setFileName(file.name);
      const items = await parseFile(file);
      if (items.length === 0) {
        setError("No valid data found in file.");
      } else {
        const result = analyzeInventory(items);
        setAnalysis(result);
      }
    } catch (err) {
      setError("Failed to parse file. Ensure it is a valid Excel/CSV format.");
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setAnalysis(null);
    setFileName("");
    setError(null);
  };

  return (
    <div className="min-h-screen bg-gray-50 pb-12">
      <nav className="bg-white border-b border-gray-200 sticky top-0 z-10 shadow-sm">
