import { GoogleGenAI } from "@google/genai";
import { AggregatedAnalysis } from "../types";

// Initialize the Gemini API client
// Note: process.env.API_KEY is automatically provided by the environment
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const formatForAI = (analysis: AggregatedAnalysis) => {
  const getTop = (list: any[]) => list.slice(0, 30).map(r => ({
    sku: r.item.sku,
    dc: r.item.dc,
    demandType: r.item.demandType,
    moh: r.item.mohTotal,
    accuracy: (r.item.accuracy * 100).toFixed(1) + '%',
    onHand: r.item.onHand,
    sales3m: r.item.threeMonthActuals,
    supplier: r.item.supplier,
    leadTime: r.item.leadTime + 'd',
    otd: (r.item.otd * 100).toFixed(0) + '%'
  }));

  return JSON.stringify({
    summary: {
      totalItems: analysis.totalItems,
      shortfallCount: analysis.shortfall.length,
      oversupplyCount: analysis.oversupply.length,
      deadStockCount: analysis.deadStock.length,
      supplierRiskCount: analysis.supplierRisk.length
    },
    criticalItems: {
      shortfalls: getTop(analysis.shortfall),
      oversupply: getTop(analysis.oversupply),
      deadStock: getTop(analysis.deadStock),
      supplierRisks: getTop(analysis.supplierRisk)
    }
  }, null, 2);
};

export const generateExecutiveReport = async (analysis: AggregatedAnalysis): Promise<{ emailText: string; htmlDashboard: string }> => {
  const dataContext = formatForAI(analysis);

  const prompt = `
    You are a World-Class Supply Chain Strategy Consultant and Inventory Analyst.

    DATA CONTEXT (JSON):
    ${dataContext}

    TASK:
    1. Write a high-impact Executive Summary in a professional email format addressed to the Director of Supply Chain. 
       - Highlight the most critical "Potential Shortfall" items.
       - Address "Supplier Risks" and their impact on fulfillment.
       - Recommend immediate actions for "Dead Stock".

    2. Create a self-contained interactive HTML/Tailwind/Chart.js dashboard.
       - It must be a single code block starting with \`\`\`html.
       - It should visualize the data provided in the context.
       - Use high-contrast colors (Red for risk, Green for healthy).

    Respond with the email text first, followed by the HTML dashboard in a markdown block.
  `;

  try {
    // Simplified contents format following guidelines
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
        topP: 0.95,
      }
    });

    const fullText = response.text || "";

    // Extract HTML dashboard using regex
    const htmlMatch = fullText.match(/```html([\s\S]*?)```/);
    const htmlDashboard = htmlMatch ? htmlMatch[1].trim() : "<!-- No dashboard generated -->";

    // The email text is everything else
    const emailText = fullText.replace(/```html[\s\S]*?```/, '').trim();

    return { emailText, htmlDashboard };
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw new Error(`AI Analysis failed: ${error.message || "Unknown error"}`);
  }
};

import { AggregatedAnalysis } from "../types";

export const generateExecutiveReport = async (
  analysis: AggregatedAnalysis, 
  token: string
): Promise<{ emailText: string; htmlDashboard: string }> => {

  const formatForAI = (analysis: AggregatedAnalysis) => {
    const getTop = (list: any[]) => list.slice(0, 20).map(r => ({
      sku: r.item.sku,
      moh: r.item.mohTotal,
      acc: r.item.accuracy,
      supplier: r.item.supplier
    }));

    return JSON.stringify({
      counts: {
        shortfall: analysis.shortfall.length,
        oversupply: analysis.oversupply.length,
        dead: analysis.deadStock.length
      },
      topRisks: getTop(analysis.shortfall)
    });
  };

  const response = await fetch('/api/analyze', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': token
    },
    body: JSON.stringify({ context: formatForAI(analysis) })
  });

  if (!response.ok) {
    const err = await response.json();
    throw new Error(err.error || "Server error during analysis");
  }

  return response.json();
};

import React, { useState, useEffect } from 'react';
import { LayoutDashboard, Loader2, AlertCircle, ShieldCheck, Lock, ArrowRight, Wifi, WifiOff } from 'lucide-react';
import { FileUpload } from './components/FileUpload';
import { AnalysisDashboard } from './components/AnalysisDashboard';
import { parseFile, analyzeInventory } from './utils/dataProcessor';
import { AggregatedAnalysis } from './types';

function App() {
  const [analysis, setAnalysis] = useState<AggregatedAnalysis | null>(null);
  const [fileName, setFileName] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Auth State
  const [token, setToken] = useState("");
  const [isAuthorized, setIsAuthorized] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);
  const [serverStatus, setServerStatus] = useState<'online' | 'offline' | 'checking'>('checking');

  useEffect(() => {
    const checkServer = async () => {
      try {
        const res = await fetch('/api/health');
        if (res.ok) setServerStatus('online');
        else setServerStatus('offline');
      } catch {
        setServerStatus('offline');
      }
    };
    checkServer();
  }, []);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsVerifying(true);
    try {
      const res = await fetch('/api/verify', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ token })
      });
      if (res.ok) setIsAuthorized(true);
      else setError("Invalid Access Token");
    } catch {
      setError("Cannot connect to security server");
    } finally {
      setIsVerifying(false);
    }
  };

  const handleFileUpload = async (file: File) => {
    setLoading(true);
    setError(null);
    try {
      setFileName(file.name);
      const items = await parseFile(file);
      const result = analyzeInventory(items);
      setAnalysis(result);
    } catch (err: any) {
      setError(`Processing failed: ${err.message}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans">
      <nav className="bg-white/80 backdrop-blur-md border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl shadow-indigo-200 shadow-lg">
              <LayoutDashboard className="w-5 h-5 text-white" />
            </div>
            <span className="font-bold text-lg tracking-tight">Inventory Agent</span>
          </div>

          <div className="flex items-center gap-4">
            {serverStatus === 'online' ? (
              <span className="text-[10px] font-bold uppercase tracking-widest text-emerald-600 bg-emerald-50 px-2 py-1 rounded-md flex items-center gap-1.5 border border-emerald-100">
                <Wifi className="w-3 h-3" /> Secure Server Active
              </span>
            ) : (
              <span className="text-[10px] font-bold uppercase tracking-widest text-rose-600 bg-rose-50 px-2 py-1 rounded-md flex items-center gap-1.5 border border-rose-100">
                <WifiOff className="w-3 h-3" /> Server Offline
              </span>
            )}
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 py-12">
        {!isAuthorized ? (
          <div className="max-w-md mx-auto mt-20 animate-in fade-in zoom-in duration-500">
            <div className="bg-white p-10 rounded-3xl border border-slate-200 shadow-2xl shadow-slate-200/50">
              <div className="text-center mb-8">
                <div className="inline-flex p-4 bg-indigo-50 rounded-2xl mb-4">
                  <ShieldCheck className="w-10 h-10 text-indigo-600" />
                </div>
                <h2 className="text-2xl font-black text-slate-900">Secure Access</h2>
                <p className="text-slate-500 text-sm mt-2">Enter your agent passcode to begin analysis</p>
              </div>

              <form onSubmit={handleAuth} className="space-y-6">
                <div className="relative">
                  <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                  <input
                    type="password"
                    placeholder="Agent Passcode"
                    value={token}
                    onChange={(e) => setToken(e.target.value)}
