                  className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all active:scale-[0.98] disabled:opacity-50 flex items-center justify-center gap-2"
                >
                  {isVerifying ? <Loader2 className="animate-spin w-5 h-5" /> : <>Access Dashboard <ArrowRight className="w-5 h-5" /></>}
                </button>
              </form>
            </div>
          </div>
        ) : loading ? (
          <div className="flex flex-col items-center justify-center py-40">
            <div className="relative">
               <Loader2 className="animate-spin h-20 w-20 text-indigo-600" />
