import { read, utils } from 'xlsx';
import { InventoryItem, RawRow, AnalysisResult, RiskCategory, AggregatedAnalysis } from '../types';

// Helper to normalize headers for fuzzy matching
const normalize = (str: string) => str.toLowerCase().replace(/[^a-z0-9]/g, '');

const COLUMN_MAPPING = {
  sku: ['sku', 'item', 'product', 'material'],
  dc: ['rowlabels', 'dc', 'location', 'site', 'plant'],
  demandType: ['demandtype', 'type', 'category'],
  mohTotal: ['moh', 'monthsonhand', 'transit', 'moh+intransit', 'totalmoh'],
  accuracy: ['accuracy', 'forecastaccuracy', '3mactualsvforecast', 'acc'],
  onHand: ['onhand', 'stock', 'quantity', 'oh'],
  threeMonthActuals: ['3mactuals', 'sales', 'usage', 'consumption', 'demand'],
  // New Mappings
  supplier: ['supplier', 'vendor', 'source'],
  leadTime: ['leadtime', 'lt', 'lead_time', 'days'],
  otd: ['otd', 'ontime', 'delivery', 'performance']
};

const findKey = (row: RawRow, possibleKeys: string[]): string | undefined => {
  const rowKeys = Object.keys(row);
  return rowKeys.find(key => possibleKeys.some(pk => normalize(key).includes(pk)));
};

export const parseFile = async (file: File): Promise<InventoryItem[]> => {
  const data = await file.arrayBuffer();
  const workbook = read(data);
  const sheetName = workbook.SheetNames[0];
  const worksheet = workbook.Sheets[sheetName];
  const jsonData = utils.sheet_to_json<RawRow>(worksheet);

  if (jsonData.length === 0) return [];

  // Determine column mapping from the first row
  const firstRow = jsonData[0];
  const map: Record<keyof typeof COLUMN_MAPPING, string | undefined> = {
    sku: findKey(firstRow, COLUMN_MAPPING.sku),
    dc: findKey(firstRow, COLUMN_MAPPING.dc),
    demandType: findKey(firstRow, COLUMN_MAPPING.demandType),
    mohTotal: findKey(firstRow, COLUMN_MAPPING.mohTotal),
    accuracy: findKey(firstRow, COLUMN_MAPPING.accuracy),
    onHand: findKey(firstRow, COLUMN_MAPPING.onHand),
    threeMonthActuals: findKey(firstRow, COLUMN_MAPPING.threeMonthActuals),
    supplier: findKey(firstRow, COLUMN_MAPPING.supplier),
    leadTime: findKey(firstRow, COLUMN_MAPPING.leadTime),
    otd: findKey(firstRow, COLUMN_MAPPING.otd),
  };

  return jsonData.map((row, index) => {
    const getItem = (key: string | undefined) => (key && row[key] !== undefined ? row[key] : 0);
    const getString = (key: string | undefined) => (key && row[key] ? String(row[key]) : 'Unknown');

    // Parse MOH - Handle "NO SALE" or other non-numeric strings
    let rawMoh = getItem(map.mohTotal);
    let mohValue = 0;
    if (typeof rawMoh === 'string') {
      const normalizedMoh = rawMoh.toUpperCase().trim();
      if (normalizedMoh === 'NO SALE' || normalizedMoh === 'N/A') {
        mohValue = 0;
      } else {
        mohValue = parseFloat(rawMoh) || 0;
      }
    } else {
      mohValue = Number(rawMoh) || 0;
    }

    // Parse percentages if they come in as strings like "80%"
    let acc = getItem(map.accuracy);
    if (typeof acc === 'string') {
      if (acc.includes('%')) {
        acc = parseFloat(acc.replace('%', '')) / 100;
      } else {
        acc = parseFloat(acc);
      }
    }

    let otd = getItem(map.otd);
    if (typeof otd === 'string') {
        if (otd.includes('%')) {
            otd = parseFloat(otd.replace('%', '')) / 100;
        } else {
            otd = parseFloat(otd);
        }
    } else {
        // If not found, default to 1.0 (100%) to avoid flagging everything if data is missing
        otd = map.otd ? Number(otd) : 1.0; 
    }

    return {
      id: `row-${index}`,
      sku: getString(map.sku),
      dc: getString(map.dc),
      demandType: getString(map.demandType),
      mohTotal: mohValue,
      accuracy: Number(acc),
      onHand: Number(getItem(map.onHand)),
      threeMonthActuals: Number(getItem(map.threeMonthActuals)),
      supplier: map.supplier ? getString(map.supplier) : 'N/A',
      leadTime: map.leadTime ? Number(getItem(map.leadTime)) : 0,
      otd: Number(otd),
      originalData: row,
    };
  });
};

export const analyzeInventory = (items: InventoryItem[]): AggregatedAnalysis => {
  const shortfall: AnalysisResult[] = [];
  const oversupply: AnalysisResult[] = [];
  const deadStock: AnalysisResult[] = [];
  const supplierRisk: AnalysisResult[] = [];

  items.forEach(item => {
    // Rule 1: Potential Shortfall
    // moh_total < 2 AND accuracy >= 0.8 AND moh_total > 0 (Exclude "NO SALE" or 0 stock items)
    if (item.mohTotal < 2 && item.mohTotal > 0 && item.accuracy >= 0.8) {
      shortfall.push({ item, risks: [RiskCategory.SHORTFALL] });
    }

    // Rule 2: Oversupply
    // moh_total > 2 AND accuracy < 0.8
    if (item.mohTotal > 2 && item.accuracy < 0.8) {
      oversupply.push({ item, risks: [RiskCategory.OVERSUPPLY] });
    }

    // Rule 3: Dead Stock
    // On Hand > 0 AND 3m Actuals == 0
    if (item.onHand > 0 && item.threeMonthActuals === 0) {
      deadStock.push({ item, risks: [RiskCategory.DEAD_STOCK] });
    }

    // Rule 4: Supplier Risk
    // Lead Time > 60 days OR OTD < 85%
    if (item.leadTime > 60 || item.otd < 0.85) {
        supplierRisk.push({ item, risks: [RiskCategory.SUPPLIER_RISK] });
    }
  });

  return {
    shortfall,
    oversupply,
    deadStock,
    supplierRisk,
    allItems: items, // Return all items for visualization context
    totalItems: items.length
  };
};

import { read, utils } from 'xlsx';
import React, { useState } from 'react';
import { Beaker, CheckCircle2, XCircle, Play, ChevronRight, Bug, Activity, Loader2 } from 'lucide-react';
import { analyzeInventory } from '../utils/dataProcessor';
import { InventoryItem, RiskCategory } from '../types';

interface TestResult {
  name: string;
  status: 'passed' | 'failed' | 'idle';
  expected: string;
  actual: string;
  duration: number;
}

export const TestSuite: React.FC<{ isOpen: boolean; onClose: () => void }> = ({ isOpen, onClose }) => {
  const [results, setResults] = useState<TestResult[]>([]);
  const [isRunning, setIsRunning] = useState(false);

  const runTests = async () => {
    setIsRunning(true);

    const mockItem = (overrides: Partial<InventoryItem>): InventoryItem => ({
      id: 'test-id',
      sku: 'TEST-SKU',
      dc: 'TEST-DC',
      demandType: 'Static',
      mohTotal: 1,
      accuracy: 0.9,
      onHand: 100,
      threeMonthActuals: 50,
      supplier: 'Test Vendor',
      leadTime: 10,
      otd: 0.95,
      originalData: {},
      ...overrides
    });

    const tests: { name: string; item: InventoryItem; expectedRisk: RiskCategory | 'Healthy' }[] = [
      {
        name: 'Shortfall Rule (MOH < 2 & Acc >= 0.8)',
        item: mockItem({ mohTotal: 1.5, accuracy: 0.85 }),
        expectedRisk: RiskCategory.SHORTFALL
      },
      {
        name: 'Shortfall Exclusion (MOH = 0 / NO SALE)',
        item: mockItem({ mohTotal: 0, accuracy: 0.99 }),
        expectedRisk: 'Healthy'
      },
      {
        name: 'Oversupply Rule (MOH > 2 & Acc < 0.8)',
        item: mockItem({ mohTotal: 4, accuracy: 0.6 }),
        expectedRisk: RiskCategory.OVERSUPPLY
      },
      {
        name: 'Dead Stock Rule (OH > 0 & Sales == 0)',
        item: mockItem({ onHand: 50, threeMonthActuals: 0 }),
        expectedRisk: RiskCategory.DEAD_STOCK
      },
      {
        name: 'Supplier Risk Rule (Lead Time > 60)',
        item: mockItem({ leadTime: 75 }),
        expectedRisk: RiskCategory.SUPPLIER_RISK
      },
      {
        name: 'Supplier Risk Rule (OTD < 85%)',
        item: mockItem({ otd: 0.70 }),
        expectedRisk: RiskCategory.SUPPLIER_RISK
      }
    ];

    const newResults: TestResult[] = tests.map(t => {
      const testStart = performance.now();
      const analysis = analyzeInventory([t.item]);

      const actualRisks: string[] = [];
      if (analysis.shortfall.length > 0) actualRisks.push(RiskCategory.SHORTFALL);
      if (analysis.oversupply.length > 0) actualRisks.push(RiskCategory.OVERSUPPLY);
      if (analysis.deadStock.length > 0) actualRisks.push(RiskCategory.DEAD_STOCK);
      if (analysis.supplierRisk.length > 0) actualRisks.push(RiskCategory.SUPPLIER_RISK);

      const actualDisplay = actualRisks.join(', ') || 'Healthy';
      const passed = t.expectedRisk === 'Healthy' ? actualDisplay === 'Healthy' : actualRisks.includes(t.expectedRisk as RiskCategory);

      return {
        name: t.name,
        status: passed ? 'passed' : 'failed',
        expected: t.expectedRisk,
        actual: actualDisplay,
        duration: Math.round(performance.now() - testStart)
      };
    });

    setTimeout(() => {
      setResults(newResults);
      setIsRunning(false);
    }, 600);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex justify-end">
      <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={onClose} />
      <div className="relative w-full max-w-lg bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
        <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-100 p-2 rounded-lg">
              <Beaker className="w-5 h-5 text-indigo-600" />
            </div>
            <div>
              <h2 className="font-black text-slate-900 text-lg uppercase tracking-tight">Diagnostic Engine</h2>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">System Integrity Verification</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-200 rounded-full transition-colors text-slate-400">
            <XCircle className="w-6 h-6" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-4">
          <div className="bg-slate-900 rounded-2xl p-6 text-white space-y-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Activity className="w-4 h-4 text-emerald-400" />
                <span className="text-xs font-bold uppercase tracking-widest">Test Runner v1.0.5</span>
              </div>
              <button 
                onClick={runTests}
                disabled={isRunning}
                className="bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 px-4 py-2 rounded-xl text-xs font-black uppercase tracking-widest flex items-center gap-2 transition-all shadow-lg shadow-indigo-500/20"
              >
                {isRunning ? <Loader2 className="w-3 h-3 animate-spin" /> : <Play className="w-3 h-3 fill-current" />}
                Run Diagnostics
              </button>
            </div>

            {results.length === 0 && !isRunning && (
              <div className="py-12 text-center text-slate-500 space-y-2">
                <Bug className="w-8 h-8 mx-auto opacity-20" />
                <p className="text-xs font-bold uppercase tracking-widest">No tests executed in this session</p>
              </div>
            )}

            {isRunning && (
              <div className="space-y-3 animate-pulse">
                {[1, 2, 3].map(i => (
                  <div key={i} className="h-12 bg-white/5 rounded-xl border border-white/5" />
                ))}
              </div>
            )}

            <div className="space-y-3">
              {results.map((res, i) => (
                <div key={i} className="bg-white/5 border border-white/10 rounded-xl p-4 flex flex-col gap-2 group hover:border-white/20 transition-all">
                  <div className="flex items-center justify-between">
                    <span className="text-[11px] font-bold text-slate-300">{res.name}</span>
                    {res.status === 'passed' ? (
                      <span className="bg-emerald-500/20 text-emerald-400 px-2 py-0.5 rounded text-[9px] font-black uppercase tracking-tighter flex items-center gap-1">
                        <CheckCircle2 className="w-3 h-3" /> Pass
                      </span>
                    ) : (
                      <span className="bg-rose-500/20 text-rose-400 px-2 py-0.5 rounded text-[9px] font-black uppercase tracking-tighter flex items-center gap-1">
                        <XCircle className="w-3 h-3" /> Fail
                      </span>
                    )}
                  </div>
                  <div className="flex items-center gap-4 text-[10px] font-mono text-slate-500">
                    <div className="flex items-center gap-1">
                      <span className="text-slate-600">Expected:</span>
                      <span className="text-emerald-500/70">{res.expected}</span>
                    </div>
                    <ChevronRight className="w-3 h-3" />
                    <div className="flex items-center gap-1">
                      <span className="text-slate-600">Actual:</span>
                      <span className={res.status === 'passed' ? 'text-emerald-500/70' : 'text-rose-500/70'}>{res.actual}</span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="p-6 border-t border-slate-100 bg-slate-50 text-center">
          <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
            Inventory Alert Agent Security Diagnostic Module
          </p>
        </div>
      </div>
    </div>
  );
};

