      mohTotal,
      accuracy: accuracyValue,
      onHand: parseNumeric(map.onHand),
      threeMonthActuals: parseNumeric(map.threeMonthActuals),
      supplier: map.supplier ? getString(map.supplier) : 'N/A',
      leadTime: parseNumeric(map.leadTime),
      otd,
      originalData: row,
    };
  });
};

export const analyzeInventory = (items: InventoryItem[]): AggregatedAnalysis => {
  const shortfall: AnalysisResult[] = [];
  const oversupply: AnalysisResult[] = [];
  const deadStock: AnalysisResult[] = [];
  const supplierRisk: AnalysisResult[] = [];

  items.forEach(item => {
    // Rule 1: Potential Shortfall
    if (item.mohTotal >= 0 && item.mohTotal < 2 && item.accuracy >= 0.8) {
      shortfall.push({ item, risks: [RiskCategory.SHORTFALL] });
    }

    // Rule 2: Oversupply
    if (item.mohTotal > 2 && item.accuracy < 0.8) {
      oversupply.push({ item, risks: [RiskCategory.OVERSUPPLY] });
    }

    // Rule 3: Dead Stock
    if (item.onHand > 0 && item.threeMonthActuals === 0) {
      deadStock.push({ item, risks: [RiskCategory.DEAD_STOCK] });
    }

    // Rule 4: Supplier Risk
    if (item.leadTime > 60 || item.otd < 0.85) {
      supplierRisk.push({ item, risks: [RiskCategory.SUPPLIER_RISK] });
    }
  });

  return { shortfall, oversupply, deadStock, supplierRisk, allItems: items, totalItems: items.length };
};

import { AggregatedAnalysis } from "../types";

const formatForAI = (analysis: AggregatedAnalysis) => {
  const getTop = (list: any[]) => list.slice(0, 30).map(r => ({
    sku: r.item.sku,
    dc: r.item.dc,
    moh: r.item.mohTotal,
    accuracy: (r.item.accuracy * 100).toFixed(1) + '%',
    onHand: r.item.onHand,
    sales3m: r.item.threeMonthActuals,
    supplier: r.item.supplier,
    leadTime: r.item.leadTime + 'd',
    otd: (r.item.otd * 100).toFixed(0) + '%'
  }));

  return {
    summary: {
      totalItems: analysis.totalItems,
      shortfallCount: analysis.shortfall.length,
      oversupplyCount: analysis.oversupply.length,
      deadStockCount: analysis.deadStock.length,
      supplierRiskCount: analysis.supplierRisk.length
    },
    criticalItems: {
      shortfalls: getTop(analysis.shortfall),
      oversupply: getTop(analysis.oversupply),
      deadStock: getTop(analysis.deadStock),
      supplierRisks: getTop(analysis.supplierRisk)
    }
  };
};

export const generateExecutiveReport = async (analysis: AggregatedAnalysis): Promise<{ emailText: string; htmlDashboard: string }> => {
  const context = formatForAI(analysis);

  try {
    const response = await fetch('/api/analyze', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'yuKVek24' // Use the same token as configured in backend
      },
      body: JSON.stringify({ context })
    });

    if (!response.ok) {
      const errData = await response.json();
      throw new Error(errData.error || 'Server-side AI analysis failed');
    }

    return await response.json();
  } catch (error: any) {
    console.error("Analysis Error:", error);
    throw new Error(`AI Analysis failed: ${error.message || "Unknown error"}`);
  }
};

