import { GoogleGenAI, Type } from "@google/genai";
import { AggregatedAnalysis } from "../types";

// Always use a named parameter and obtain from process.env.API_KEY.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const formatForAI = (analysis: AggregatedAnalysis) => {
  const getTop = (list: any[]) => list.slice(0, 30).map(r => ({
    sku: r.item.sku,
    dc: r.item.dc,
    moh: r.item.mohTotal,
    accuracy: (r.item.accuracy * 100).toFixed(1) + '%',
    onHand: r.item.onHand,
    sales3m: r.item.threeMonthActuals,
    supplier: r.item.supplier,
    leadTime: r.item.leadTime + 'd',
    otd: (r.item.otd * 100).toFixed(0) + '%'
  }));

  return {
    summary: {
      totalItems: analysis.totalItems,
      shortfallCount: analysis.shortfall.length,
      oversupplyCount: analysis.oversupply.length,
      deadStockCount: analysis.deadStock.length,
      supplierRiskCount: analysis.supplierRisk.length
    },
    criticalItems: {
      shortfalls: getTop(analysis.shortfall),
      oversupply: getTop(analysis.oversupply),
      deadStock: getTop(analysis.deadStock),
      supplierRisks: getTop(analysis.supplierRisk)
    }
  };
};

/**
 * Generates an executive inventory report using Gemini.
 * Uses gemini-3-pro-preview for advanced reasoning on inventory risks.
 */
export const generateExecutiveReport = async (analysis: AggregatedAnalysis): Promise<{ emailText: string; htmlDashboard: string }> => {
  const context = formatForAI(analysis);

  try {
    // Call generateContent with model name and contents.
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [{
        parts: [{
          text: `You are a senior supply chain intelligence agent. 
          Analyze the following inventory risk context and generate:
          1. A professional email summary (emailText) for an executive.
          2. A condensed HTML dashboard snippet (htmlDashboard) for quick visual assessment.

          Data: ${JSON.stringify(context)}`
        }]
      }],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            emailText: {
              type: Type.STRING,
              description: 'Professional email body summarizing critical inventory findings.',
            },
            htmlDashboard: {
              type: Type.STRING,
              description: 'HTML string for an executive dashboard view.',
            },
          },
          required: ["emailText", "htmlDashboard"],
        },
      },
    });

    // Access the .text property directly (not a method).
    const jsonStr = response.text.trim();
    const result = JSON.parse(jsonStr);

    if (!result.emailText || !result.htmlDashboard) {
      throw new Error("Invalid AI response structure.");
    }

    return result;
  } catch (error: any) {
    console.error("Analysis Error:", error);
    throw new Error(`AI Analysis failed: ${error.message || "Unknown error"}`);
  }
};

